
class SecretList {final String apiVersion; final String kind; final ListMeta? metadata; final List<Secret> items; SecretList({this.apiVersion = 'v1', this.kind = 'SecretList', this.metadata, required this.items}); factory SecretList.fromJson(Map<String, dynamic> json) {return SecretList(apiVersion: json['apiVersion'] ?? 'v1', kind: json['kind'] ?? 'SecretList', metadata: json['metadata'] != null ? ListMeta.fromJson(json['metadata']) : null, items: (json['items'] as List).map((e) => Secret.fromJson(e)).toList());} Map<String, dynamic> toJson() {return {'apiVersion' : apiVersion, 'kind' : kind, if (metadata != null) 'metadata' : metadata!.toJson(), 'items' : items.map((e) => e.toJson()).toList()};}}
